def normalize_public_language(language):
    code = (language or "").split(",", 1)[0].split(";", 1)[0].split("-", 1)[0].lower()
    supported = {item[0] for item in PUBLIC_LANGUAGES}
    return code if code in supported else DEFAULT_PUBLIC_LANGUAGE


def detect_public_language(request):
    explicit = request.session.get(PUBLIC_LANGUAGE_SESSION_KEY) or request.COOKIES.get(PUBLIC_LANGUAGE_SESSION_KEY)
    if explicit:
        return normalize_public_language(explicit)
    try:
        from clients.translation import CLIENT_LANGUAGE_SESSION_KEY
    except ImportError:
        CLIENT_LANGUAGE_SESSION_KEY = "client_language"
    shared = request.session.get(CLIENT_LANGUAGE_SESSION_KEY) or request.COOKIES.get(CLIENT_LANGUAGE_SESSION_KEY)
    if shared:
        return normalize_public_language(shared)
    for item in (request.META.get("HTTP_ACCEPT_LANGUAGE") or "").split(","):
        lang = normalize_public_language(item)
        if lang != DEFAULT_PUBLIC_LANGUAGE or item.lower().startswith(DEFAULT_PUBLIC_LANGUAGE):
            return lang
    return DEFAULT_PUBLIC_LANGUAGE


def public_texts(language):
    language = normalize_public_language(language)
    return {**PUBLIC_TRANSLATIONS[DEFAULT_PUBLIC_LANGUAGE], **PUBLIC_TRANSLATIONS.get(language, {})}


def localize_items(items, translations, language):
    language = normalize_public_language(language)
    localized = []
    for item in items:
        data = {**item}
        data.update(translations.get(item["slug"], {}).get(language, {}))
        if language in ("de", "fr") and not translations.get(item["slug"], {}).get(language):
            data.update(translations.get(item["slug"], {}).get("en", {}))
        localized.append(data)
    return localized
